sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {

    var body      = request.body.data;
    var startTime = body ? body.startTime : null;
    var endTime   = body ? body.endTime   : null;

    if (!startTime || !endTime) {
        response.setStatus(400);
        response.setBody({ error: 'startTime and endTime are required' });
        return;
    }

    var availability = new x_608645_my_comp_0.LessonAvailability();

    if (availability.hasStudentBookedThisWeek(gs.getUserID())) {
        response.setStatus(400);
        response.setBody({ error: 'You already have a lesson booked this week.' });
        return;
    }

    if (!availability.isSlotAvailable(startTime, endTime)) {
        response.setStatus(400);
        response.setBody({ error: 'Slot no longer available. Please choose another.' });
        return;
    }

    // Find an available teacher for this slot
    var teacherSysId = '';
    var roleGr = new GlideRecord('sys_user_has_role');
    roleGr.addQuery('role', '1835f20d83100310345ba730ceaad351');
    roleGr.addQuery('user.active', true);
    roleGr.query();
    while (roleGr.next()) {
        var tId   = roleGr.getValue('user');
        var check = new GlideRecord('x_608645_my_comp_0_lesson');
        check.addQuery('teacher', tId);
        check.addQuery('start_time', startTime);
        check.addQuery('status', 'NOT IN', 'no_show');
        check.query();
        if (!check.hasNext()) {
            teacherSysId = tId;
            break;
        }
    }

    if (!teacherSysId) {
        response.setStatus(400);
        response.setBody({ error: 'No available teacher for this slot.' });
        return;
    }

    var lesson = new GlideRecord('x_608645_my_comp_0_lesson');
    lesson.initialize();
    lesson.setValue('student',    gs.getUserID());
    lesson.setValue('teacher',    teacherSysId);
    lesson.setValue('start_time', startTime);
    lesson.setValue('end_time',   endTime);
    lesson.setValue('status',     'scheduled');
    var sysId = lesson.insert();

    response.setStatus(201);
    response.setBody({ success: true, sys_id: sysId });

})(request, response);
